import React, { useEffect, useMemo, useState } from 'react';
import axios from 'axios';
import L from 'leaflet';
import {
  MapContainer,
  Marker,
  Popup,
  TileLayer,
  useMap,
  useMapEvents,
} from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import './App.css';

delete (L.Icon.Default.prototype as { _getIconUrl?: unknown })._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',
  iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
});

type CitySummary = {
  name: string;
  country: string;
  condition: string;
  temperature_c: number;
  latitude: number;
  longitude: number;
};

type ForecastItem = {
  day: string;
  condition: string;
  min_temp_c: number;
  max_temp_c: number;
  precipitation_chance: number;
};

type HourlyForecastItem = {
  time: string;
  condition: string;
  temperature_c: number;
  precipitation_chance: number;
};

type WeatherDetails = {
  city: string;
  country: string;
  latitude: number;
  longitude: number;
  updated_at: string;
  condition: string;
  temperature_c: number;
  feels_like_c: number;
  humidity: number;
  wind_speed: number;
  pressure_mmhg: number;
  visibility_km: number;
  forecast: ForecastItem[];
  hourly_forecast: HourlyForecastItem[];
};

type Overview = {
  title: string;
  description: string;
  cities_count: number;
  highlight: {
    city: string;
    temperature_c: number;
    condition: string;
  };
};

type SelectionMode = 'city' | 'coordinates';

type CoordinatePoint = {
  latitude: number;
  longitude: number;
};

type FavoritePoint = {
  id: string;
  label: string;
  country: string;
  latitude: number;
  longitude: number;
};

const FAVORITES_STORAGE_KEY = 'weather-favorites';
const THEME_STORAGE_KEY = 'weather-theme';
const DEFAULT_CENTER: CoordinatePoint = {
  latitude: 55.7558,
  longitude: 37.6176,
};
const BARNAUL_CITY_NAME = 'Р‘Р°СЂРЅР°СѓР»';

const RAIN_LAYER_URL =
  'https://tilecache.rainviewer.com/v2/radar/nowcast_0/256/{z}/{x}/{y}/6/1_1.png';

function MapClickHandler({
  onSelect,
}: {
  onSelect: (point: CoordinatePoint) => void;
}) {
  useMapEvents({
    click(event) {
      onSelect({
        latitude: event.latlng.lat,
        longitude: event.latlng.lng,
      });
    },
  });

  return null;
}

function RecenterMap({ center }: { center: [number, number] }) {
  const map = useMap();

  useEffect(() => {
    map.setView(center, Math.max(map.getZoom(), 5));
  }, [center, map]);

  return null;
}

function App() {
  const [cities, setCities] = useState<CitySummary[]>([]);
  const [selectedCity, setSelectedCity] = useState<string>('');
  const [selectionMode, setSelectionMode] = useState<SelectionMode>('city');
  const [selectedPoint, setSelectedPoint] = useState<CoordinatePoint | null>(null);
  const [weather, setWeather] = useState<WeatherDetails | null>(null);
  const [overview, setOverview] = useState<Overview | null>(null);
  const [favorites, setFavorites] = useState<FavoritePoint[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [weatherLoading, setWeatherLoading] = useState<boolean>(false);
  const [error, setError] = useState<string>('');
  const [theme, setTheme] = useState<'light' | 'dark'>('light');

  useEffect(() => {
    const rawFavorites = window.localStorage.getItem(FAVORITES_STORAGE_KEY);
    if (!rawFavorites) {
      return;
    }

    try {
      setFavorites(JSON.parse(rawFavorites) as FavoritePoint[]);
    } catch (storageError) {
      console.error(storageError);
    }
  }, []);

  useEffect(() => {
    const storedTheme = window.localStorage.getItem(THEME_STORAGE_KEY);
    if (storedTheme === 'dark' || storedTheme === 'light') {
      setTheme(storedTheme);
    }
  }, []);

  useEffect(() => {
    window.localStorage.setItem(FAVORITES_STORAGE_KEY, JSON.stringify(favorites));
  }, [favorites]);

  useEffect(() => {
    window.localStorage.setItem(THEME_STORAGE_KEY, theme);
  }, [theme]);

  useEffect(() => {
    const loadInitialData = async () => {
      try {
        setLoading(true);
        const [citiesResponse, overviewResponse] = await Promise.all([
          axios.get<CitySummary[]>('/api/cities'),
          axios.get<Overview>('/api/overview'),
        ]);

        setCities(citiesResponse.data);
        setOverview(overviewResponse.data);

        if (citiesResponse.data.length > 0) {
          const initialCity =
            citiesResponse.data.find((city) => city.name === BARNAUL_CITY_NAME) ??
            citiesResponse.data[0];
          setSelectedCity(initialCity.name);
          setSelectedPoint({
            latitude: initialCity.latitude,
            longitude: initialCity.longitude,
          });
        }
      } catch (requestError) {
        setError('РќРµ СѓРґР°Р»РѕСЃСЊ Р·Р°РіСЂСѓР·РёС‚СЊ СЃРїРёСЃРѕРє РіРѕСЂРѕРґРѕРІ Рё СЃРІРѕРґРєСѓ.');
        console.error(requestError);
      } finally {
        setLoading(false);
      }
    };

    loadInitialData();
  }, []);

  useEffect(() => {
    if (!selectedCity || selectionMode !== 'city') {
      return;
    }

    const loadWeatherByCity = async () => {
      try {
        setError('');
        setWeatherLoading(true);
        const response = await axios.get<WeatherDetails>('/api/weather', {
          params: { city: selectedCity },
        });
        setWeather(response.data);
        setSelectedPoint({
          latitude: response.data.latitude,
          longitude: response.data.longitude,
        });
        setCities((currentCities) =>
          currentCities.map((city) =>
            city.name === response.data.city
              ? {
                  ...city,
                  condition: response.data.condition,
                  temperature_c: response.data.temperature_c,
                }
              : city
          )
        );
      } catch (requestError) {
        setError('РќРµ СѓРґР°Р»РѕСЃСЊ Р·Р°РіСЂСѓР·РёС‚СЊ РґР°РЅРЅС‹Рµ Рѕ РїРѕРіРѕРґРµ.');
        console.error(requestError);
      } finally {
        setWeatherLoading(false);
      }
    };

    loadWeatherByCity();
  }, [selectedCity, selectionMode]);

  useEffect(() => {
    if (!selectedPoint || selectionMode !== 'coordinates') {
      return;
    }

    const loadWeatherByCoordinates = async () => {
      try {
        setError('');
        setWeatherLoading(true);
        const response = await axios.get<WeatherDetails>('/api/weather/by-coordinates', {
          params: {
            latitude: selectedPoint.latitude,
            longitude: selectedPoint.longitude,
          },
        });
        setWeather(response.data);
      } catch (requestError) {
        setError('РќРµ СѓРґР°Р»РѕСЃСЊ Р·Р°РіСЂСѓР·РёС‚СЊ РїСЂРѕРіРЅРѕР· РґР»СЏ РІС‹Р±СЂР°РЅРЅРѕР№ С‚РѕС‡РєРё.');
        console.error(requestError);
      } finally {
        setWeatherLoading(false);
      }
    };

    loadWeatherByCoordinates();
  }, [selectedPoint, selectionMode]);

  const heroCity = weather
    ? {
        city: weather.city,
        temperature_c: weather.temperature_c,
        condition: weather.condition,
      }
    : overview?.highlight;

  const mapCenter = useMemo<[number, number]>(() => {
    if (selectedPoint) {
      return [selectedPoint.latitude, selectedPoint.longitude];
    }

    return [DEFAULT_CENTER.latitude, DEFAULT_CENTER.longitude];
  }, [selectedPoint]);

  const isCurrentFavorite = useMemo(() => {
    if (!weather) {
      return false;
    }

    return favorites.some(
      (favorite) =>
        favorite.latitude === weather.latitude && favorite.longitude === weather.longitude
    );
  }, [favorites, weather]);

  const selectableCities = useMemo(
    () => cities.filter((city) => city.name === BARNAUL_CITY_NAME),
    [cities]
  );

  const formatTemperature = (temperature: number) => {
    const roundedTemperature = Math.ceil(temperature);
    const sign = roundedTemperature > 0 ? '+' : '';

    return `${sign}${roundedTemperature}\u00B0C`;
  };

  const handleCitySelect = (city: CitySummary) => {
    setSelectionMode('city');
    setSelectedCity(city.name);
    setSelectedPoint({
      latitude: city.latitude,
      longitude: city.longitude,
    });
  };

  const handleMapSelect = (point: CoordinatePoint) => {
    setSelectionMode('coordinates');
    setSelectedPoint(point);
  };

  const handleAddFavorite = () => {
    if (!weather || isCurrentFavorite) {
      return;
    }

    setFavorites((currentFavorites) => [
      {
        id: `${weather.latitude}_${weather.longitude}`,
        label: weather.city,
        country: weather.country,
        latitude: weather.latitude,
        longitude: weather.longitude,
      },
      ...currentFavorites,
    ]);
  };

  const handleFavoriteSelect = (favorite: FavoritePoint) => {
    setSelectionMode('coordinates');
    setSelectedPoint({
      latitude: favorite.latitude,
      longitude: favorite.longitude,
    });
  };

  const handleFavoriteRemove = (favoriteId: string) => {
    setFavorites((currentFavorites) =>
      currentFavorites.filter((favorite) => favorite.id !== favoriteId)
    );
  };

  const handleThemeToggle = () => {
    setTheme((currentTheme) => (currentTheme === 'light' ? 'dark' : 'light'));
  };

  return (
    <div className={`app-shell app-shell--${theme}`}>
      <main className="page">
        <div className="page-toolbar">
          <button className="theme-toggle" onClick={handleThemeToggle} type="button">
            {theme === 'light' ? 'РўС‘РјРЅР°СЏ С‚РµРјР°' : 'РЎРІРµС‚Р»Р°СЏ С‚РµРјР°'}
          </button>
        </div>

        <section className="hero hero--centered">
          <div className="hero__panel">
            <p className="hero__panel-label">{overview?.title ?? 'РЎРІРѕРґРєР°'}</p>
            <h2>{heroCity?.city ?? 'Р—Р°РіСЂСѓР·РєР°...'}</h2>
            <p className="hero__temperature">
              {heroCity ? formatTemperature(heroCity.temperature_c) : '--'}
            </p>
            <p className="hero__condition">{heroCity?.condition ?? ''}</p>
            <p className="hero__meta">
              Р“РѕСЂРѕРґРѕРІ РІ СЃРµСЂРІРёСЃРµ: {overview?.cities_count ?? 0}
            </p>
            <p className="hero__meta">
              Р РµР¶РёРј: {selectionMode === 'city' ? 'РїРѕ РіРѕСЂРѕРґСѓ' : 'РїРѕ РєРѕРѕСЂРґРёРЅР°С‚Р°Рј'}
            </p>
          </div>
        </section>

        <section className="dashboard">
          <div className="controls-card">
            <div>
              <p className="section-label">Р’С‹Р±РѕСЂ РіРѕСЂРѕРґР°</p>
              <h3>Быстрый переход к готовым локациям</h3>
            </div>

            <div className="city-grid">
              {selectableCities.map((city) => (
                <button
                  key={city.name}
                  className={`city-chip ${
                    selectionMode === 'city' && selectedCity === city.name
                      ? 'city-chip--active'
                      : ''
                  }`}
                  onClick={() => handleCitySelect(city)}
                  type="button"
                >
                  <span>{city.name}</span>
                  <small>
                    {formatTemperature(city.temperature_c)} В· {city.condition}
                  </small>
                </button>
              ))}
            </div>

            <div className="favorites-panel">
              <div className="favorites-panel__header">
                <p className="section-label">РР·Р±СЂР°РЅРЅРѕРµ</p>
              </div>

              <div className="favorites-list">
                {favorites.length === 0 && (
                  <p className="favorites-empty">РџРѕРєР° РЅРµС‚ СЃРѕС…СЂР°РЅРµРЅРЅС‹С… С‚РѕС‡РµРє.</p>
                )}

                {favorites.map((favorite) => (
                  <div className="favorite-item" key={favorite.id}>
                    <button
                      className="favorite-item__main"
                      onClick={() => handleFavoriteSelect(favorite)}
                      type="button"
                    >
                      <strong>{favorite.label}</strong>
                      <span>{favorite.country}</span>
                      <small>
                        {favorite.latitude.toFixed(4)}, {favorite.longitude.toFixed(4)}
                      </small>
                    </button>
                    <button
                      className="favorite-item__remove"
                      onClick={() => handleFavoriteRemove(favorite.id)}
                      type="button"
                    >
                      РЈРґР°Р»РёС‚СЊ
                    </button>
                  </div>
                ))}
              </div>
            </div>
          </div>

          <div className="weather-card">
            {(loading || weatherLoading) && <p className="status">Р—Р°РіСЂСѓР¶Р°РµРј РґР°РЅРЅС‹Рµ...</p>}
            {!loading && error && <p className="status status--error">{error}</p>}

            {!loading && weather && (
              <>
                <div className="weather-card__header">
                  <div>
                    <p className="section-label">РЎРµР№С‡Р°СЃ</p>
                    <h2>
                      {weather.city}, {weather.country}
                    </h2>
                    <p className="updated-at">РћР±РЅРѕРІР»РµРЅРѕ: {weather.updated_at}</p>
                  </div>

                  <div className="weather-card__hero-value">
                    {formatTemperature(weather.temperature_c)}
                  </div>
                </div>

                <p className="weather-condition">{weather.condition}</p>
                <div className="metrics-grid">
                  <article className="metric">
                    <span>РћС‰СѓС‰Р°РµС‚СЃСЏ РєР°Рє</span>
                    <strong>{formatTemperature(weather.feels_like_c)}</strong>
                  </article>
                  <article className="metric">
                    <span>Р’Р»Р°Р¶РЅРѕСЃС‚СЊ</span>
                    <strong>{weather.humidity}%</strong>
                  </article>
                  <article className="metric">
                    <span>Р’РµС‚РµСЂ</span>
                    <strong>{weather.wind_speed} Рј/СЃ</strong>
                  </article>
                  <article className="metric">
                    <span>Р”Р°РІР»РµРЅРёРµ</span>
                    <strong>{weather.pressure_mmhg} РјРј СЂС‚. СЃС‚.</strong>
                  </article>
                  <article className="metric">
                    <span>Р’РёРґРёРјРѕСЃС‚СЊ</span>
                    <strong>{weather.visibility_km} РєРј</strong>
                  </article>
                </div>
              </>
            )}
          </div>
        </section>



        <section className="map-card">
          <div className="map-card__header">
            <div>
              <p className="section-label">РљР°СЂС‚Р°</p>
              <h3>РќР°Р¶РјРёС‚Рµ РЅР° РєР°СЂС‚Сѓ РґР»СЏ РїСЂРѕРіРЅРѕР·Р° РїРѕ РєРѕРѕСЂРґРёРЅР°С‚Р°Рј</h3>
            </div>
            <p>
              Р‘Р°Р·РѕРІР°СЏ РєР°СЂС‚Р° OpenStreetMap
            </p>
          </div>

          <div className="map-card__body">
            <div className="map-frame">
              <MapContainer
                attributionControl={false}
                center={mapCenter}
                zoom={5}
                maxZoom={10}
                className="leaflet-map"
                scrollWheelZoom
              >
                <RecenterMap center={mapCenter} />
                <TileLayer
                  maxZoom={19}
                  url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
                />
                <TileLayer
                  maxNativeZoom={10}
                  maxZoom={10}
                  opacity={0.55}
                  url={RAIN_LAYER_URL}
                />
                {selectedPoint && (
                  <Marker position={[selectedPoint.latitude, selectedPoint.longitude]}>
                    <Popup>
                      <div className="popup-weather">
                        <strong>{weather?.city ?? 'Р’С‹Р±СЂР°РЅРЅР°СЏ С‚РѕС‡РєР°'}</strong>
                        <span>
                          {weather ? formatTemperature(weather.temperature_c) : 'Р—Р°РіСЂСѓР·РєР°...'}
                        </span>
                        <span>{weather?.condition ?? 'РџРѕР»СѓС‡Р°РµРј РґР°РЅРЅС‹Рµ Рѕ РїРѕРіРѕРґРµ'}</span>
                      </div>
                    </Popup>
                  </Marker>
                )}
                <MapClickHandler onSelect={handleMapSelect} />
              </MapContainer>
              <div className="custom-attribution">
                РСЃС‚РѕС‡РЅРёРєРё: OpenStreetMap contributors, RainViewer
              </div>
            </div>

            <div className="map-card__info">
              <div className="map-card__info-panel">
                <span>Избранное</span>
                <strong>
                  <button
                    className="favorite-action"
                    disabled={!weather || isCurrentFavorite}
                    onClick={handleAddFavorite}
                    type="button"
                  >
                    {isCurrentFavorite ? 'Уже в избранном' : 'Добавить в избранное'}
                  </button>
                </strong>
              </div>
              <div className="map-card__info-panel">
                <span>РћРїСЂРµРґРµР»РµРЅРЅС‹Р№ РіРѕСЂРѕРґ</span>
                <strong>{weather ? `${weather.city}, ${weather.country}` : 'Р—Р°РіСЂСѓР·РєР°...'}</strong>
              </div>
            </div>
          </div>
        </section>

        <section className="hourly-card">
          <div className="forecast-card__header">
            <div>
              <p className="section-label">РџРѕС‡Р°СЃРѕРІРѕР№ РїСЂРѕРіРЅРѕР·</p>
              <h3>РџРѕРіРѕРґР° РЅР° 24 С‡Р°СЃР°</h3>
            </div>
            <p>Р”Р»СЏ РІС‹Р±СЂР°РЅРЅРѕР№ С‚РѕС‡РєРё СЃ С€Р°РіРѕРј РІ 1 С‡Р°СЃ.</p>
          </div>

          <div className="hourly-scroll" role="region" aria-label="РџРѕС‡Р°СЃРѕРІРѕР№ РїСЂРѕРіРЅРѕР· РЅР° 24 С‡Р°СЃР°">
            <div className="hourly-grid">
              {weather?.hourly_forecast.map((hour) => (
                <article className="hourly-item" key={`${hour.time}-${hour.condition}`}>
                  <p className="hourly-item__time">{hour.time}</p>
                  <strong>{hour.condition}</strong>
                  <p className="hourly-item__temp">{formatTemperature(hour.temperature_c)}</p>
                  <p className="hourly-item__precipitation">
                    Р’РµСЂРѕСЏС‚РЅРѕСЃС‚СЊ РѕСЃР°РґРєРѕРІ: {hour.precipitation_chance}%
                  </p>
                </article>
              ))}
            </div>
          </div>
        </section>

        <section className="forecast-card">
          <div className="forecast-card__header">
            <div>
              <p className="section-label">РџСЂРѕРіРЅРѕР·</p>
              <h3>Р‘Р»РёР¶Р°Р№С€РёРµ 5 РґРЅРµР№</h3>
            </div>
            <p>{overview?.description}</p>
          </div>

          <div className="forecast-grid">
            {weather?.forecast.map((day) => (
              <article className="forecast-item" key={day.day}>
                <p className="forecast-item__day">{day.day}</p>
                <strong>{day.condition}</strong>
                <p>
                  {formatTemperature(day.min_temp_c)} / {formatTemperature(day.max_temp_c)}
                </p>
                <span>РћСЃР°РґРєРё: {day.precipitation_chance}%</span>
              </article>
            ))}
          </div>
        </section>
      </main>
    </div>
  );
}

export default App;
